(function(){'use strict';let modal=null;let modalTitle=null;let modalMessage=null;let modalUrl=null;let modalContinue=null;let modalCancel=null;let currentLink=null;let focusableElements=[];let firstFocusable=null;let lastFocusable=null;function init(){document.addEventListener('click',handleLinkClick);modal=document.getElementById('wz-ela-modal');if(!modal){return}
modalTitle=modal.querySelector('#wz-ela-modal-title');modalMessage=modal.querySelector('#wz-ela-modal-message');modalUrl=modal.querySelector('.wz-ela-modal-url');modalContinue=modal.querySelector('[data-wz-ela-continue]');modalCancel=modal.querySelector('.wz-ela-modal-cancel');if(typeof wzElaSettings!=='undefined'){modalTitle.textContent=wzElaSettings.modalTitle;modalMessage.textContent=wzElaSettings.modalMessage;modalContinue.textContent=wzElaSettings.continueText;modalCancel.textContent=wzElaSettings.cancelText}
modal.querySelectorAll('[data-wz-ela-close]').forEach(function(element){element.addEventListener('click',closeModal)});modalContinue.addEventListener('click',handleContinue);modal.addEventListener('keydown',handleKeydown)}
function handleLinkClick(e){const link=e.target.closest('a[data-wz-ela-external]');if(!link){return}
const method=typeof wzElaSettings!=='undefined'?wzElaSettings.warningMethod:'inline';if('redirect'===method||'inline_redirect'===method){const redirectUrl=link.getAttribute('data-wz-ela-redirect-url');if(redirectUrl){e.preventDefault();window.location.href=redirectUrl;return}}
if('modal'===method||'inline_modal'===method){e.preventDefault();currentLink=link;showModal(link)}}
function showModal(link){const url=link.getAttribute('data-wz-ela-url');modalUrl.textContent=url;modal.removeAttribute('hidden');document.body.classList.add('wz-ela-modal-active');setupFocusTrap();if(firstFocusable){firstFocusable.focus()}}
function closeModal(){modal.setAttribute('hidden','');document.body.classList.remove('wz-ela-modal-active');if(currentLink){currentLink.focus()}
currentLink=null}
function handleContinue(){if(!currentLink){return}
const url=currentLink.getAttribute('data-wz-ela-url');window.open(url,'_blank','noopener,noreferrer');closeModal()}
function setupFocusTrap(){focusableElements=modal.querySelectorAll('button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])');firstFocusable=focusableElements[0];lastFocusable=focusableElements[focusableElements.length-1]}
function handleKeydown(e){if('Escape'===e.key){closeModal();return}
if('Tab'===e.key){if(e.shiftKey){if(document.activeElement===firstFocusable){e.preventDefault();lastFocusable.focus()}}else{if(document.activeElement===lastFocusable){e.preventDefault();firstFocusable.focus()}}}}
if('loading'===document.readyState){document.addEventListener('DOMContentLoaded',init)}else{init()}})()